mapper.sql:
(case a.biz_type
    when 2 then (select cardName from fit_card where fitCardId = p.product_id)
    when 3 then (select card_name from vip_benefit_card where vip_card_id = p.product_id)
    else (select product_name from pt_product where id = p.product_id)
end)

(case a.biz_type
    when 2 then (select cardPrice from fit_card where fitCardId = p.product_id)
    when 3 then (select price from vip_benefit_card where vip_card_id = p.product_id)
    else (select sale_price from pt_product where id = p.product_id)
end)

(case a.biz_type
    when 2 then (select cardImgUrl from fit_card where fitCardId = p.product_id)
    when 3 then null
    else (select cover_url from pt_product where id = p.product_id)
end)

mapper.select:
SELECT COUNT(*) FROM card_order
WHERE userId = #{userId} AND flash_sale_activity_id = #{activityId} AND cardId = #{productId}
  AND status IN (1, 2, 3, 4)

SELECT COUNT(*) FROM vip_benefit
WHERE user_id = #{userId} AND flash_sale_activity_id = #{activityId} AND vip_card_id = #{productId}
  AND status IN (0, 1, 2, 3)
